import * as React from "react";
import { useState, useEffect } from "react";
import { 
  makeStyles, 
  shorthands, 
  Button, 
  Title2, 
  Divider 
} from "@fluentui/react-components";
import { LockClosedRegular } from "@fluentui/react-icons";
import StyleMapper from "./StyleMapper";
import LicenseGate from "./LicenseGate";

const useStyles = makeStyles({
  root: {
    minHeight: "100vh",
    backgroundColor: "#f5f5f5",
    ...shorthands.padding("20px"),
    display: "flex",
    flexDirection: "column",
    ...shorthands.gap("20px"),
  },
  header: {
    marginBottom: "10px",
  },
  footer: {
    marginTop: "auto",
    ...shorthands.padding("20px", "0"),
    display: "flex",
    justifyContent: "center",
  },
});

const App = (props) => {
  const styles = useStyles();
  const [isAuthed, setIsAuthed] = useState(false);
  const VALID_KEY = "PREMIUM-2026-USER";

  // Check license on mount
  useEffect(() => {
    const savedKey = localStorage.getItem("addin_license_key");
    if (savedKey === VALID_KEY) {
      setIsAuthed(true);
    }
  }, []);

  // Handle successful activation
  const handleAuthSuccess = () => {
    setIsAuthed(true);
  };

  // Handle Logout
  const handleLogout = () => {
    localStorage.removeItem("addin_license_key");
    // Optionally clear style preferences too if you want a full reset
    // localStorage.removeItem("style_mapper_prefs");
    window.location.reload();
  };

  if (!isAuthed) {
    return <LicenseGate onNotifyAuth={handleAuthSuccess} />;
  }

  return (
    <div className={styles.root}>
      <header className={styles.header}>
        <Title2 block>{props.title}</Title2>
      </header>

      <main>
        <StyleMapper />
      </main>

      <Divider />

      <footer className={styles.footer}>
        <Button 
          appearance="subtle" 
          size="small" 
          icon={<LockClosedRegular />} 
          onClick={handleLogout}
        >
          Logout / Reset License
        </Button>
      </footer>
    </div>
  );
};

export default App;