import * as React from "react";
import { useState } from "react";
import { 
  makeStyles, 
  shorthands, 
  Button, 
  Input, 
  Label, 
  Title3, 
  Body1,
  Field,
  MessageBar,
  MessageBarTitle,
  MessageBarBody
} from "@fluentui/react-components";
import { KeyRegular } from "@fluentui/react-icons";

const useStyles = makeStyles({
  container: {
    display: "flex",
    flexDirection: "column",
    ...shorthands.gap("20px"),
    ...shorthands.padding("40px", "20px"),
    textAlign: "center",
  },
  card: {
    backgroundColor: "white",
    ...shorthands.padding("25px"),
    ...shorthands.borderRadius("8px"),
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    display: "flex",
    flexDirection: "column",
    ...shorthands.gap("15px"),
  },
});

const LicenseGate = ({ onNotifyAuth }) => {
  const styles = useStyles();
  const [key, setKey] = useState("");
  const [error, setError] = useState(false);

  const VALID_KEY = "PREMIUM-2026-USER";

  const handleActivate = () => {
    if (key.trim() === VALID_KEY) {
      localStorage.setItem("addin_license_key", key.trim());
      onNotifyAuth(); // This tells App.jsx to switch to the StyleMapper
    } else {
      setError(true);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.card}>
        <Title3 color="#0078d4">Activation Required</Title3>
        <Body1>Please enter your premium license key to access MatterCues Style Converter tool.</Body1>

        <Field 
          label="License Key" 
          validationState={error ? "error" : "none"}
          validationMessage={error ? "Invalid key. Please try again." : ""}
        >
          <Input 
            contentBefore={<KeyRegular />}
            placeholder="PREMIUM-XXXX-USER"
            value={key}
            onChange={(e) => {
              setKey(e.target.value);
              if (error) setError(false); // Clear error while typing
            }}
          />
        </Field>

        <Button appearance="primary" onClick={handleActivate}>
          Activate License
        </Button>
      </div>

      {error && (
        <MessageBar intent="error">
          <MessageBarBody>
            <MessageBarTitle>Validation Failed</MessageBarTitle>
            Check your key or contact support.
          </MessageBarBody>
        </MessageBar>
      )}
    </div>
  );
};

export default LicenseGate;